const item = $input.first();
const headers = item.json.headers || {};
const receivedSecret = headers['x-fluxperf-webhook-secret'] || headers['X-Fluxperf-Webhook-Secret'];
const expectedSecret = $vars.MYFLUXPERF_WEBHOOK_SECRET;

if (!expectedSecret) {
  throw new Error('MYFLUXPERF_WEBHOOK_SECRET is not configured in n8n variables.');
}

if (receivedSecret !== expectedSecret) {
  throw new Error('Unauthorized MyFluxperf webhook request.');
}

const rawPayload = item.json.body?.payload ?? item.json.payload;
const payload = typeof rawPayload === 'string' ? JSON.parse(rawPayload) : rawPayload;

if (!payload?.requestId || !payload?.requester?.email || !payload?.request?.message) {
  throw new Error('Invalid MyFluxperf intervention payload.');
}

const serviceLabels = {
  visibility_acquisition: 'Flux Visibilité & Acquisition',
  automation_ai: 'Flux Automatisation & IA',
  assistant_ai: 'Flux Assistant IA'
};
const needLabels = {
  content_update: 'Mise à jour de contenus',
  technical_issue: 'Anomalie technique site',
  new_creation: 'Nouvelle création',
  page_creation: 'Création / ajout de page',
  seo: 'Référencement SEO',
  advertising_campaign: 'Campagne publicitaire',
  tracking_analytics: 'Tracking / analytics',
  performance_optimization: 'Performance / optimisation',
  automation: 'Automatisation',
  dashboard_reporting: 'Tableau de bord / reporting',
  process_automation: 'Automatisation de processus',
  tool_integration: 'Connexion outils / intégration',
  workflow_issue: 'Anomalie workflow',
  data_sync: 'Données / synchronisation',
  ai_prompt_optimization: 'Optimisation IA / prompt',
  scenario_improvement: 'Amélioration de scénario',
  ai_assistant: 'Assistant IA',
  answer_adjustment: 'Ajustement des réponses',
  knowledge_base: 'Base de connaissances',
  prompt_instructions: 'Consignes / prompts',
  access_issue: 'Accès ou anomalie',
  new_capability: 'Nouvelle capacité',
  conversation_analysis: 'Analyse / amélioration',
  user_support: 'Accompagnement utilisateur',
  other: 'Autre demande'
};
const priorityLabels = {
  normal: 'Priorité normale',
  urgent: 'Priorité urgente',
  critical: 'Priorité critique'
};

const request = payload.request;
const binary = item.binary || {};
const files = Object.entries(binary).map(([binaryProperty, file]) => ({
  binaryProperty,
  fileName: file.fileName || binaryProperty,
  mimeType: file.mimeType || 'application/octet-stream',
  fileSize: file.fileSize || null
}));

const serviceLabel = serviceLabels[request.service] || request.service;
const priorityLabel = priorityLabels[request.priority] || request.priority;
const needText = (request.needs || []).map((need) => needLabels[need] || need).join(', ');
const selectedSolutions = Array.isArray(request.selectedSolutions) ? request.selectedSolutions : [];
const legacySelectedSites = Array.isArray(request.selectedSites) ? request.selectedSites : [];
const legacySiteText = legacySelectedSites
  .map((site) => `${site.domain || site.url || site.id}${site.type ? ` (${site.type})` : ``}`)
  .join(', ');
const solutionText = selectedSolutions
  .map((solution) => {
    const name = solution.name || solution.typeLabel || solution.type || solution.id || 'Solution Fluxperf';
    const target = solution.domain || solution.url || '';
    const type = solution.typeLabel || serviceLabels[solution.type] || solution.type || '';
    const details = [target, type].filter(Boolean).join(' - ');

    return details ? `${name} (${details})` : name;
  })
  .join(', ') || legacySiteText || 'Non applicable';
const requesterName = [payload.requester.firstName, payload.requester.lastName].filter(Boolean).join(' ');
const clientName = payload.client.companyName || 'Client Fluxperf';

const cardName = `[${payload.requestId}] ${clientName} - ${serviceLabel}`;
const cardDescription = [
  `Référence : ${payload.requestId}`,
  `Date : ${payload.submittedAt}`,
  `Client : ${clientName} (${payload.client.id || 'sans id'})`,
  `Demandeur : ${requesterName || payload.requester.email} <${payload.requester.email}>`,
  `Service : ${serviceLabel}`,
  `Solution : ${solutionText}`,
  `Besoin : ${needText}`,
  `Priorité : ${priorityLabel}`,
  `Pièces jointes : ${files.length}`,
  '',
  'Message client :',
  request.message
].join('\\n');

return [{
  json: {
    requestId: payload.requestId,
    submittedAt: payload.submittedAt,
    payload,
    normalized: {
      serviceLabel,
      priorityLabel,
      needText,
      solutionText,
      legacySiteText,
      requesterName,
      clientName,
      fileCount: files.length,
      files
    },
    trello: {
      cardName,
      cardDescription
    }
  },
  binary
}];

const normalized = $('Validate + Normalize').first().json;
const createdCard = $('Trello - Create Card').first().json;
const binary = $('Validate + Normalize').first().binary || {};
const binaryKeys = Object.keys(binary);

if (binaryKeys.length === 0) {
  return [{
    json: {
      requestId: normalized.requestId,
      cardId: createdCard.id,
      skipAttachment: true
    }
  }];
}

return binaryKeys.map((binaryProperty) => ({
  json: {
    requestId: normalized.requestId,
    cardId: createdCard.id,
    binaryProperty,
    skipAttachment: false
  },
  binary: {
    data: binary[binaryProperty]
  }
}));

const normalized = $('Validate + Normalize').first().json;
const payload = normalized.payload;
const prompt = [
  'Tu es responsable de clientèle pour Fluxperf.',
  'Rédige uniquement le corps d\'un email d\'accusé de réception.',
  'Contraintes : moins de 300 caractères, ton professionnel, réponse adaptée à la demande, pas d\'objet, pas de variables non résolues.',
  'Termine exactement par : L\'équipe Fluxperf',
  '',
  `Client : ${normalized.normalized.clientName}`,
  `Service : ${normalized.normalized.serviceLabel}`,
  `Besoin : ${normalized.normalized.needText}`,
  `Priorité : ${normalized.normalized.priorityLabel}`,
  `Message client : ${payload.request.message}`
].join('\n');

return [{
  json: {
    requestId: normalized.requestId,
    requesterEmail: payload.requester.email,
    requesterName: normalized.normalized.requesterName,
    openaiBody: {
      model: $vars.OPENAI_MODEL || 'gpt-5.6-luna',
      input: prompt,
      max_output_tokens: 140
    }
  }
}];

const openaiResponse = $input.first().json;
const normalized = $('Validate + Normalize').first().json;
const payload = normalized.payload;

const outputText = openaiResponse.output_text
  || (openaiResponse.output || [])
    .flatMap((output) => output.content || [])
    .map((content) => content.text || '')
    .join('')
    .trim()
  || 'Bonjour, nous avons bien reçu votre demande. Notre équipe va l\'examiner et reviendra vers vous dans les meilleurs délais. L\'équipe Fluxperf';

const escapedText = outputText
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\n/g, '<br>');

return [{
  json: {
    requestId: normalized.requestId,
    cardId: $('Trello - Create Card').first().json.id,
    aiReply: outputText,
    brevoBody: {
      sender: {
        name: 'Fluxperf',
        email: 'notifications@fluxperf.fr'
      },
      to: [
        {
          email: payload.requester.email,
          name: normalized.normalized.requesterName || payload.requester.email
        }
      ],
      subject: `Demande reçue - ${normalized.requestId}`,
      htmlContent: `<p>${escapedText}</p>`,
      textContent: outputText
    }
  }
}];

